[GQL-OP discover]
  query {
    products(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US"
      filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id) availability:InStock" first: 10) {
      totalCount
      items { id name availabilityData { isInStock isTrackInventory availableQuantity } }
    }
  }
[GQL-EXEC discover]
[GQL-CAPTURE discover.data.products.items[0].id → PRODUCT_ID_A]
[GQL-CAPTURE discover.data.products.items[1].id → PRODUCT_ID_B]
[GQL-OP add_a]
  mutation {
    addItem(command: { storeId: "{{STORE_ID}}" cartName: "default" userId: "{{USER_ID}}"
      currencyCode: "USD" cultureName: "en-US" productId: "{{PRODUCT_ID_A}}" quantity: 1 }) { id itemsCount }
  }
[GQL-EXEC add_a]
[GQL-OP add_b]
  mutation {
    addItem(command: { storeId: "{{STORE_ID}}" cartName: "default" userId: "{{USER_ID}}"
      currencyCode: "USD" cultureName: "en-US" productId: "{{PRODUCT_ID_B}}" quantity: 1 }) { id itemsCount }
  }
