      currencyCode: "USD" cultureName: "en-US" lineItemId: "{{LINE_ITEM_ID_B}}" quantity: {{OVER_STOCK_QTY}} }) { id itemsCount }
  }
[GQL-EXEC change_b_overstock]
[GQL-OP read_back]
  query {
    cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") {
