[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cleanup_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US" }) { id } }
[GQL-EXEC cleanup_pre]
[GQL-OP add_item]
  mutation {
    addItem(command: {
      storeId: "{{STORE_ID}}"
      cartName: "default"
      userId: "{{USER_ID}}"
      currencyCode: "USD"
      cultureName: "en-US"
      productId: "{{PRODUCT_ID}}"
      quantity: 1
    }) {
      id itemsCount
    }
  }
[GQL-EXEC add_item]
[GQL-OP get_line_id]
  query {
    cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") {
      itemsCount
      items { id productId quantity }
    }
  }
[GQL-EXEC get_line_id]
[GQL-CAPTURE get_line_id.data.cart.items[?productId={{PRODUCT_ID}}].id → LINE_ITEM_ID]
[GQL-OP change_to_overstock]
  mutation {
    changeCartItemQuantity(command: {
      storeId: "{{STORE_ID}}"
      cartName: "default"
      userId: "{{USER_ID}}"
      currencyCode: "USD"
      cultureName: "en-US"
      lineItemId: "{{LINE_ITEM_ID}}"
      quantity: {{OVER_STOCK_QTY}}
    }) {
      id itemsCount
    }
  }
[GQL-EXEC change_to_overstock]
[GQL-OP read_foo]
  query {
    cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") {
      itemsCount
      validationErrors(ruleSet: "foo") {
        errorCode
        objectId
        objectType
        errorMessage
      }
    }
  }
[GQL-EXEC read_foo]
[GQL-OP read_wildcard]
  query {
    cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") {
      itemsCount
      validationErrors(ruleSet: "*") {
        errorCode
        objectId
        objectType
        errorMessage
      }
    }
  }
[GQL-EXEC read_wildcard]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US" }) { id } }
[GQL-EXEC cleanup_post]

[AUTH role=USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP list_cards_before]
  query {
    skyflowCards(storeId: "{{STORE_ID}}") {
      cards {
        skyflowId
        cardNumber
        cardType
        cardScheme
        cardholderName
        expiryMonth
        expiryYear
        active
      }
    }
  }
[GQL-EXEC list_cards_before]
[GQL-CAPTURE list_cards_before.data.skyflowCards.cards[1].skyflowId → DISPOSABLE_SKYFLOW_ID]
[GQL-OP delete_card]
  mutation {
    deleteSkyflowCard(command: {
      skyflowId: "{{DISPOSABLE_SKYFLOW_ID}}"
      storeId: "{{STORE_ID}}"
    })
  }
[GQL-EXEC delete_card]
[GQL-OP list_cards_after]
  query {
    skyflowCards(storeId: "{{STORE_ID}}") {
      cards { skyflowId cardNumber active }
    }
  }
[GQL-EXEC list_cards_after]
